#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        double p = 1.0 / K;
        double expectedLength = 2 + (N - 1) * (1 - p) * 2;
        printf("%.2f\n", expectedLength);
    }
    return 0;
}

