import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            double p = 1.0 / K;
            double expectedLength = 2 + (N - 1) * (1 - p) * 2;
            System.out.printf("%.2f\n", expectedLength);
        }
    }
}

